using SkiaSharp;
using System.Text;
using System.Text.RegularExpressions;

Regex containsBlankTextElement = new Regex(@">\s+</text>");
int numTextElementsPerTask = 10;
int bugCount = 0;

Func<int, string> drawSvgFunc = (int taskI) => {
    Console.WriteLine($"Start task {taskI}");
    byte[] svgBytes;
    using (var svgStream = new MemoryStream()) {
        using (var canvas = SKSvgCanvas.Create(new SKRect(0, 0, 500, 500), svgStream)) {
            for (int i = 0; i < numTextElementsPerTask; i++) {
                using var paint = new SKPaint { Style = SKPaintStyle.Fill, Color = SKColors.Black };
                using var typeface = SKTypeface.FromFamilyName("Arial");
                using var font = typeface.ToFont(14);
                var align = SKTextAlign.Left;
                var text = $"Hello, World {i + 1} of {numTextElementsPerTask}!";
                canvas.DrawText(text, 10, i * 15 + 20, align, font, paint);
            }
        }
        svgStream.Position = 0;
        svgBytes = svgStream.ToArray();
    }
    var svgStringDecoded = Encoding.UTF8.GetString(svgBytes);
    bool containsBlankText = containsBlankTextElement.IsMatch(svgStringDecoded);
    if (containsBlankText) {
        Interlocked.Increment(ref bugCount);
        Console.WriteLine($"**bug found** during generation task {taskI}");
    } else {
        Console.WriteLine($"bug not found during generation task {taskI}");
    }
    return svgStringDecoded;
};

Console.WriteLine("****** SYNCHRONOUS CALLS ******");
for (int syncAttempt = 0; syncAttempt < 5; syncAttempt++) {
    await Task.Run(() => drawSvgFunc(syncAttempt));
}

Console.WriteLine("****** PARALLEL CALLS ******");
await Task.WhenAll(
    Enumerable.Range(0, 5)
    .Select(i => Task.Run(() => drawSvgFunc(i)))
).ConfigureAwait(false);

if (bugCount > 0)
    Console.WriteLine($"FAILURE: Bug reproduced in {bugCount} tasks");
else
    Console.WriteLine("SUCCESS: test completed - no bugs found");

Console.WriteLine("Done");

proposedResponse.body:
Thanks for the thorough report and reproduction project!

We were able to reproduce this issue on Windows with both SkiaSharp 3.116.0 and 3.119.1. The parallel section consistently produces empty `<text>` elements (2-5 of 5 tasks affected per run), while the synchronous section works correctly every time.

**Good news:** Testing against the current main branch source shows the bug appears to be fixed — 5 consecutive runs all passed with zero failures. This fix hasn't been released yet.

**Tested versions:**
| Version | Result |
|---------|--------|
| 3.116.0 (NuGet) | ❌ Reproduced (2-5/5 parallel tasks affected) |
| 3.119.1 (NuGet) | ❌ Reproduced (3-5/5 parallel tasks affected) |
| main branch (source) | ✅ Not reproduced (0/5 across 5 runs) |

**Workaround:** Until the fix ships in a stable release, you can serialize SVG text generation to avoid the race condition:

```csharp
private static readonly SemaphoreSlim _svgLock = new(1, 1);

await _svgLock.WaitAsync();
try {
    using var canvas = SKSvgCanvas.Create(bounds, svgStream);
    // ... draw text ...
} finally {
    _svgLock.Release();
}
```
